import React from 'react';
import { Link as RouterLink } from 'react-router-dom';
import {
    AppBar,
    Toolbar,
    Typography,
    Link,
    Box,
    Container,
    Button,
} from '@mui/material';
import SecurityIcon from '@mui/icons-material/Security';

const Navigation: React.FC = () => {
    return (
        <AppBar position="sticky" sx={{ background: 'linear-gradient(90deg, #667eea 0%, #764ba2 100%)', boxShadow: '0 4px 20px rgba(0,0,0,0.1)' }}>
            <Container maxWidth="lg">
                <Toolbar disableGutters sx={{ justifyContent: 'space-between' }}>
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                        <SecurityIcon sx={{ fontSize: 32 }} />
                        <Typography
                            variant="h6"
                            sx={{
                                fontWeight: 'bold',
                                background: 'linear-gradient(90deg, #fff 0%, #f0f0f0 100%)',
                                backgroundClip: 'text',
                                textFillColor: 'transparent',
                            }}
                        >
                            Cybersecurity IDS
                        </Typography>
                    </Box>
                    <Box sx={{ display: 'flex', gap: 2 }}>
                        <Button
                            color="inherit"
                            component={RouterLink}
                            to="/"
                            sx={{
                                textTransform: 'none',
                                fontSize: '1rem',
                                fontWeight: 500,
                                '&:hover': { opacity: 0.8 },
                            }}
                        >
                            Home
                        </Button>
                        <Button
                            color="inherit"
                            component={RouterLink}
                            to="/upload"
                            sx={{
                                textTransform: 'none',
                                fontSize: '1rem',
                                fontWeight: 500,
                                '&:hover': { opacity: 0.8 },
                            }}
                        >
                            Upload
                        </Button>
                        <Button
                            color="inherit"
                            component={RouterLink}
                            to="/results"
                            sx={{
                                textTransform: 'none',
                                fontSize: '1rem',
                                fontWeight: 500,
                                '&:hover': { opacity: 0.8 },
                            }}
                        >
                            Results
                        </Button>
                    </Box>
                </Toolbar>
            </Container>
        </AppBar>
    );
};

export default Navigation;
